import React, { useState, useEffect } from "react";
import { Toaster, toast } from "react-hot-toast";


const App = () => {
  const [notes, setNotes] = useState([]);
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");

  // Load notes from localStorage
  useEffect(() => {
    const savedNotes = JSON.parse(localStorage.getItem("notes")) || [];
    setNotes(savedNotes);
  }, []);

  // Save to localStorage when notes change
  useEffect(() => {
    localStorage.setItem("notes", JSON.stringify(notes));
  }, [notes]);

  const addNote = () => {
    if (!title || !content) {
      toast.error("Please enter both title and content!");
      return;
    }
    const newNote = {
      id: Date.now(),
      title,
      content,
    };
    setNotes([...notes, newNote]);
    setTitle("");
    setContent("");
    toast.success("Note added successfully!");
  };

  const deleteNote = (id) => {
    const updatedNotes = notes.filter((n) => n.id !== id);
    setNotes(updatedNotes);
    toast.success("Note deleted!");
  };

  const editNote = (id) => {
    const noteToEdit = notes.find((n) => n.id === id);
    const newTitle = prompt("Edit Title:", noteToEdit.title);
    const newContent = prompt("Edit Content:", noteToEdit.content);
    if (newTitle && newContent) {
      const updatedNotes = notes.map((n) =>
        n.id === id ? { ...n, title: newTitle, content: newContent } : n
      );
      setNotes(updatedNotes);
      toast.success("Note updated!");
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 py-10">
      <Toaster position="top-center" />

      <div className="max-w-2xl mx-auto bg-white p-6 rounded-2xl shadow-lg">
        <h1 className="text-3xl font-bold text-center text-blue-600 mb-4">
          📝 My Notes App
        </h1>

        {/* Input Form */}
        <div className="space-y-3 mb-5">
          <input
            type="text"
            placeholder="Note Title"
            className="w-full p-2 border rounded focus:outline-none bg-gray-100"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <textarea
            placeholder="Write your note..."
            className="w-full p-2 border rounded focus:outline-none bg-gray-100"
            rows="3"
            value={content}
            onChange={(e) => setContent(e.target.value)}
          />
          <button
            onClick={addNote}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-800 transition-all w-full"
          >
            Add Note
          </button>
        </div>

        {/* Notes List */}
        {notes.length === 0 ? (
          <p className="text-center text-gray-500">No notes yet. Add one!</p>
        ) : (
          <div className="grid gap-4">
            {notes.map((note) => (
              <NoteCard
                key={note.id}
                note={note}
                onDelete={deleteNote}
                onEdit={editNote}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
